import { useState } from 'react';

interface Todo {
  id: number;
  text: string;
  completed: boolean;
}

type Filter = 'all' | 'active' | 'completed';

export default function TodoApp() {
  const [todos, setTodos] = useState<Todo[]>([
    { id: 1, text: 'Learn React hooks', completed: true },
    { id: 2, text: 'Build a to-do app', completed: false },
    { id: 3, text: 'Deploy to Vercel', completed: false },
  ]);
  const [input, setInput] = useState('');
  const [filter, setFilter] = useState<Filter>('all');
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editText, setEditText] = useState('');

  // CREATE -- add a new to-do
  const addTodo = () => {
    if (!input.trim()) return;
    setTodos([...todos, { id: Date.now(), text: input.trim(), completed: false }]);
    setInput('');
  };

  // UPDATE -- toggle completed
  const toggleTodo = (id: number) => {
    setTodos(todos.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  };

  // UPDATE -- rename a to-do
  const saveEdit = (id: number) => {
    setTodos(todos.map(t => t.id === id ? { ...t, text: editText } : t));
    setEditingId(null);
  };

  // DELETE
  const deleteTodo = (id: number) => {
    setTodos(todos.filter(t => t.id !== id));
  };

  // READ -- filtered view
  const visible = todos.filter(t => {
    if (filter === 'active') return !t.completed;
    if (filter === 'completed') return t.completed;
    return true;
  });

  const remaining = todos.filter(t => !t.completed).length;

  return (
    <div style={{ maxWidth: 480, margin: '0 auto', padding: 32 }}>
      <h1>To-Do List</h1>

      {/* Input */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 16 }}>
        <input
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => e.key === 'Enter' && addTodo()}
          placeholder="What needs to be done?"
          style={{ flex: 1, padding: 10, borderRadius: 6, border: '1px solid #ccc' }}
        />
        <button onClick={addTodo} style={{ padding: '10px 20px' }}>Add</button>
      </div>

      {/* Filter tabs */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
        {(['all', 'active', 'completed'] as Filter[]).map(f => (
          <button
            key={f}
            onClick={() => setFilter(f)}
            style={{
              padding: '6px 14px', borderRadius: 6, border: 'none', cursor: 'pointer',
              backgroundColor: filter === f ? '#1976d2' : '#eee',
              color: filter === f ? 'white' : '#333',
            }}
          >
            {f.charAt(0).toUpperCase() + f.slice(1)}
          </button>
        ))}
      </div>

      {/* List */}
      {visible.map(todo => (
        <div key={todo.id} style={{
          display: 'flex', alignItems: 'center', gap: 8,
          padding: 10, borderBottom: '1px solid #eee',
        }}>
          <input
            type="checkbox"
            checked={todo.completed}
            onChange={() => toggleTodo(todo.id)}
          />
          {editingId === todo.id ? (
            <input
              value={editText}
              onChange={e => setEditText(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && saveEdit(todo.id)}
              onBlur={() => saveEdit(todo.id)}
              autoFocus
              style={{ flex: 1, padding: 4 }}
            />
          ) : (
            <span
              onDoubleClick={() => { setEditingId(todo.id); setEditText(todo.text); }}
              style={{
                flex: 1,
                textDecoration: todo.completed ? 'line-through' : 'none',
                color: todo.completed ? '#999' : '#333',
              }}
            >
              {todo.text}
            </span>
          )}
          <button onClick={() => deleteTodo(todo.id)} style={{ color: 'red', border: 'none', background: 'none', cursor: 'pointer' }}>
            ✕
          </button>
        </div>
      ))}

      {/* Footer */}
      <p style={{ marginTop: 12, color: '#666', fontSize: 14 }}>
        {remaining} item{remaining !== 1 ? 's' : ''} remaining
      </p>
    </div>
  );
}

import { useState } from 'react';

interface WeatherData {
  city: string;
  temperature: number;
  description: string;
  humidity: number;
  wind: number;
  forecast: { day: string; high: number; low: number; icon: string }[];
}

// Simulates an API call -- replace with a real fetch in production
async function fetchWeather(city: string): Promise<WeatherData> {
  await new Promise(r => setTimeout(r, 800)); // simulate network delay
  const cities: Record<string, WeatherData> = {
    'new york': {
      city: 'New York', temperature: 22, description: 'Partly cloudy',
      humidity: 65, wind: 12,
      forecast: [
        { day: 'Mon', high: 24, low: 18, icon: '\u2600' },
        { day: 'Tue', high: 22, low: 17, icon: '\u26c5' },
        { day: 'Wed', high: 19, low: 14, icon: '\ud83c\udf27' },
        { day: 'Thu', high: 21, low: 15, icon: '\u26c5' },
        { day: 'Fri', high: 25, low: 19, icon: '\u2600' },
      ],
    },
    'london': {
      city: 'London', temperature: 16, description: 'Light rain',
      humidity: 80, wind: 18,
      forecast: [
        { day: 'Mon', high: 17, low: 12, icon: '\ud83c\udf27' },
        { day: 'Tue', high: 15, low: 10, icon: '\ud83c\udf27' },
        { day: 'Wed', high: 18, low: 13, icon: '\u26c5' },
        { day: 'Thu', high: 20, low: 14, icon: '\u2600' },
        { day: 'Fri', high: 19, low: 13, icon: '\u26c5' },
      ],
    },
    'tokyo': {
      city: 'Tokyo', temperature: 28, description: 'Sunny',
      humidity: 55, wind: 8,
      forecast: [
        { day: 'Mon', high: 30, low: 24, icon: '\u2600' },
        { day: 'Tue', high: 29, low: 23, icon: '\u2600' },
        { day: 'Wed', high: 27, low: 22, icon: '\u26c5' },
        { day: 'Thu', high: 26, low: 21, icon: '\ud83c\udf27' },
        { day: 'Fri', high: 28, low: 23, icon: '\u2600' },
      ],
    },
  };
  const data = cities[city.toLowerCase()];
  if (!data) throw new Error(`City "${city}" not found. Try New York, London, or Tokyo.`);
