}

export default function WeatherDashboard() {
  const [city, setCity] = useState('');
  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSearch = async () => {
    if (!city.trim()) return;
    setLoading(true);
    setError('');
    try {
      const data = await fetchWeather(city);
      setWeather(data);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Something went wrong');
      setWeather(null);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ maxWidth: 520, margin: '0 auto', padding: 32 }}>
      <h1>Weather Dashboard</h1>

      {/* Search */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 20 }}>
        <input
          value={city}
          onChange={e => setCity(e.target.value)}
          onKeyDown={e => e.key === 'Enter' && handleSearch()}
          placeholder="Enter city name..."
          style={{ flex: 1, padding: 10, borderRadius: 6, border: '1px solid #ccc' }}
        />
        <button onClick={handleSearch} disabled={loading} style={{ padding: '10px 20px' }}>
          {loading ? 'Loading...' : 'Search'}
        </button>
      </div>

      {/* Error */}
      {error && (
        <div style={{ padding: 12, backgroundColor: '#fdecea', color: '#b71c1c', borderRadius: 8, marginBottom: 16 }}>
          {error}
        </div>
      )}

      {/* Current weather */}
      {weather && (
        <>
          <div style={{
            padding: 24, borderRadius: 12, backgroundColor: '#e3f2fd', textAlign: 'center', marginBottom: 16,
          }}>
            <h2 style={{ margin: 0 }}>{weather.city}</h2>
            <div style={{ fontSize: 48, fontWeight: 'bold', margin: '8px 0' }}>{weather.temperature}°C</div>
            <p style={{ margin: 0, color: '#666' }}>{weather.description}</p>
            <div style={{ display: 'flex', justifyContent: 'center', gap: 24, marginTop: 12 }}>
              <span>Humidity: {weather.humidity}%</span>
              <span>Wind: {weather.wind} km/h</span>
            </div>
          </div>

          {/* 5-day forecast */}
          <h3>5-Day Forecast</h3>
          <div style={{ display: 'flex', gap: 8 }}>
            {weather.forecast.map(day => (
              <div key={day.day} style={{
                flex: 1, textAlign: 'center', padding: 12, borderRadius: 8, border: '1px solid #ddd',
              }}>
                <div style={{ fontWeight: 'bold' }}>{day.day}</div>
                <div style={{ fontSize: 24 }}>{day.icon}</div>
                <div style={{ fontSize: 14 }}>{day.high}° / {day.low}°</div>
              </div>
            ))}
          </div>
        </>
      )}
    </div>
  );
}

