  sender: string;
  text: string;
  time: string;
  isOwn: boolean;
}

interface Channel {
  name: string;
  messages: Message[];
}

const initialChannels: Channel[] = [
  {
    name: 'general',
    messages: [
      { id: 1, sender: 'Alice', text: 'Hey everyone! Welcome to the chat.', time: '9:00 AM', isOwn: false },
      { id: 2, sender: 'Bob', text: 'Thanks Alice! Excited to be here.', time: '9:01 AM', isOwn: false },
      { id: 3, sender: 'You', text: 'Hello! Great to meet you all.', time: '9:02 AM', isOwn: true },
    ],
  },
  {
    name: 'help',
    messages: [
      { id: 1, sender: 'Charlie', text: 'Can someone explain useEffect?', time: '10:15 AM', isOwn: false },
