          color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontSize: 14, fontWeight: 'bold', marginRight: 8, flexShrink: 0,
        }}>
          {message.sender[0]}
        </div>
      )}
      <div style={{
        maxWidth: '65%', padding: '10px 14px', borderRadius: 12,
        backgroundColor: message.isOwn ? '#6366f1' : '#f3f4f6',
        color: message.isOwn ? 'white' : '#1f2937',
      }}>
        {!message.isOwn && <div style={{ fontSize: 12, fontWeight: 600, marginBottom: 2 }}>{message.sender}</div>}
        <div>{message.text}</div>
        <div style={{ fontSize: 11, opacity: 0.7, textAlign: 'right', marginTop: 4 }}>{message.time}</div>
      </div>
