];

type Category = 'all' | 'nature' | 'urban';

export default function ImageGallery() {
  const [selected, setSelected] = useState<number | null>(null);
  const [category, setCategory] = useState<Category>('all');

  const filtered = images.filter(img => category === 'all' || img.category === category);
  const selectedIndex = selected !== null ? filtered.findIndex(img => img.id === selected) : -1;

  const navigate = useCallback((direction: 'prev' | 'next') => {
    if (selectedIndex === -1) return;
    const newIndex = direction === 'next'
      ? (selectedIndex + 1) % filtered.length
      : (selectedIndex - 1 + filtered.length) % filtered.length;
    setSelected(filtered[newIndex].id);
  }, [selectedIndex, filtered]);

  // Keyboard navigation
  useEffect(() => {
    if (selected === null) return;
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setSelected(null);
      if (e.key === 'ArrowRight') navigate('next');
      if (e.key === 'ArrowLeft') navigate('prev');
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [selected, navigate]);

  const currentImage = filtered.find(img => img.id === selected);

  return (
    <div style={{ maxWidth: 800, margin: '0 auto', padding: 32 }}>
      <h1>Image Gallery</h1>

      {/* Category filter */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 20 }}>
        {(['all', 'nature', 'urban'] as Category[]).map(cat => (
          <button
            key={cat}
            onClick={() => setCategory(cat)}
            style={{
              padding: '6px 16px', borderRadius: 20, border: 'none', cursor: 'pointer',
              backgroundColor: category === cat ? '#6366f1' : '#e5e7eb',
              color: category === cat ? 'white' : '#374151',
            }}
          >
            {cat.charAt(0).toUpperCase() + cat.slice(1)}
          </button>
        ))}
      </div>

      {/* Grid */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))', gap: 12 }}>
        {filtered.map(img => (
          <div
            key={img.id}
            onClick={() => setSelected(img.id)}
            style={{ cursor: 'pointer', borderRadius: 8, overflow: 'hidden', position: 'relative' }}
          >
            <img src={img.src} alt={img.title} style={{ width: '100%', height: 140, objectFit: 'cover', display: 'block' }} />
            <div style={{ padding: '8px 10px', fontSize: 13, fontWeight: 500 }}>{img.title}</div>
          </div>
        ))}
      </div>

      {/* Lightbox overlay */}
      {currentImage && (
        <div
          onClick={() => setSelected(null)}
          style={{
            position: 'fixed', inset: 0, backgroundColor: 'rgba(0,0,0,0.85)',
            display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000,
          }}
        >
          <button onClick={e => { e.stopPropagation(); navigate('prev'); }}
            style={{ position: 'absolute', left: 20, fontSize: 32, background: 'none', border: 'none', color: 'white', cursor: 'pointer' }}>&#8592;</button>
          <div onClick={e => e.stopPropagation()} style={{ textAlign: 'center' }}>
            <img src={currentImage.src} alt={currentImage.title} style={{ maxWidth: '80vw', maxHeight: '70vh', borderRadius: 8 }} />
            <p style={{ color: 'white', marginTop: 12, fontSize: 18 }}>{currentImage.title}</p>
            <p style={{ color: '#aaa', fontSize: 14 }}>{selectedIndex + 1} / {filtered.length}</p>
          </div>
          <button onClick={e => { e.stopPropagation(); navigate('next'); }}
            style={{ position: 'absolute', right: 20, fontSize: 32, background: 'none', border: 'none', color: 'white', cursor: 'pointer' }}>&#8594;</button>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';

interface CalcState {
  display: string;
  previous: number | null;
  operator: string | null;
  resetDisplay: boolean;
}

const initialState: CalcState = {
  display: '0',
  previous: null,
  operator: null,
  resetDisplay: false,
};

export default function Calculator() {
  const [state, setState] = useState<CalcState>(initialState);

  const inputDigit = (digit: string) => {
    setState(prev => {
      if (prev.resetDisplay) {
        return { ...prev, display: digit, resetDisplay: false };
      }
      return { ...prev, display: prev.display === '0' ? digit : prev.display + digit };
    });
  };

  const inputDecimal = () => {
    setState(prev => {
      if (prev.resetDisplay) return { ...prev, display: '0.', resetDisplay: false };
      if (prev.display.includes('.')) return prev;
      return { ...prev, display: prev.display + '.' };
    });
  };

  const calculate = (left: number, op: string, right: number): number => {
    switch (op) {
      case '+': return left + right;
      case '-': return left - right;
      case '*': return left * right;
      case '/': return right !== 0 ? left / right : 0;
      default: return right;
    }
  };

  const handleOperator = (nextOp: string) => {
    setState(prev => {
      const current = parseFloat(prev.display);
      if (prev.previous !== null && prev.operator && !prev.resetDisplay) {
        const result = calculate(prev.previous, prev.operator, current);
        return { display: String(result), previous: result, operator: nextOp, resetDisplay: true };
      }
      return { display: prev.display, previous: current, operator: nextOp, resetDisplay: true };
    });
  };

  const handleEquals = () => {
    setState(prev => {
      if (prev.previous === null || !prev.operator) return prev;
      const current = parseFloat(prev.display);
      const result = calculate(prev.previous, prev.operator, current);
      return { display: String(result), previous: null, operator: null, resetDisplay: true };
    });
  };

  const clear = () => setState(initialState);

  // Keyboard support
  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (e.key >= '0' && e.key <= '9') inputDigit(e.key);
      else if (e.key === '.') inputDecimal();
      else if (['+', '-', '*', '/'].includes(e.key)) handleOperator(e.key);
      else if (e.key === 'Enter' || e.key === '=') handleEquals();
      else if (e.key === 'Escape') clear();
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  });

  const btnStyle = (bg = '#e5e7eb', color = '#111') => ({
    padding: 16, fontSize: 18, border: 'none', borderRadius: 8,
    cursor: 'pointer', backgroundColor: bg, color, fontWeight: 500 as const,
  });

  return (
    <div style={{ maxWidth: 320, margin: '0 auto', padding: 32 }}>
      <h1>Calculator</h1>
      <div style={{
        backgroundColor: '#1f2937', color: 'white', padding: '20px 16px',
        borderRadius: '12px 12px 0 0', textAlign: 'right', fontSize: 32, fontFamily: 'monospace',
        minHeight: 60, display: 'flex', alignItems: 'center', justifyContent: 'flex-end',
      }}>
        {state.display}
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 4, backgroundColor: '#f3f4f6', padding: 4, borderRadius: '0 0 12px 12px' }}>
        <button onClick={clear} style={{ ...btnStyle('#ef4444', 'white'), gridColumn: 'span 2' }}>C</button>
        <button onClick={() => handleOperator('/')} style={btnStyle('#6366f1', 'white')}>/</button>
        <button onClick={() => handleOperator('*')} style={btnStyle('#6366f1', 'white')}>*</button>
        {['7','8','9'].map(d => <button key={d} onClick={() => inputDigit(d)} style={btnStyle()}>{d}</button>)}
        <button onClick={() => handleOperator('-')} style={btnStyle('#6366f1', 'white')}>-</button>
        {['4','5','6'].map(d => <button key={d} onClick={() => inputDigit(d)} style={btnStyle()}>{d}</button>)}
        <button onClick={() => handleOperator('+')} style={btnStyle('#6366f1', 'white')}>+</button>
        {['1','2','3'].map(d => <button key={d} onClick={() => inputDigit(d)} style={btnStyle()}>{d}</button>)}
        <button onClick={handleEquals} style={{ ...btnStyle('#10b981', 'white'), gridRow: 'span 2' }}>=</button>
        <button onClick={() => inputDigit('0')} style={{ ...btnStyle(), gridColumn: 'span 2' }}>0</button>
        <button onClick={inputDecimal} style={btnStyle()}>.</button>
      </div>
    </div>
  );
}

